13	final class SquirrelApplicationDelegate: NSObject, NSApplicationDelegate, SPUStandardUserDriverDelegate, UNUserNotificationCenterDelegate {
14	  static let rimeWikiURL = URL(string: "https://github.com/rime/home/wiki")!
15	  static let updateNotificationIdentifier = "SquirrelUpdateNotification"
16	  static let notificationIdentifier = "SquirrelNotification"
17	
18	  let rimeAPI: RimeApi_stdbool = rime_get_api_stdbool().pointee
19	  var config: SquirrelConfig?
20	  var panel: SquirrelPanel?
21	  var enableNotifications = false
22	  var showStatusIcon: Bool = true
23	  var statusItem: NSStatusItem?
24	  let updateController = SPUStandardUpdaterController(startingUpdater: true, updaterDelegate: nil, userDriverDelegate: nil)
25	  var supportsGentleScheduledUpdateReminders: Bool {
26	    true
27	  }
28	
29	  func standardUserDriverWillHandleShowingUpdate(_ handleShowingUpdate: Bool, forUpdate update: SUAppcastItem, state: SPUUserUpdateState) {
30	    NSApp.setActivationPolicy(.regular)
31	    if !state.userInitiated {
32	      NSApp.dockTile.badgeLabel = "1"
33	      let content = UNMutableNotificationContent()
34	      content.title = NSLocalizedString("A new update is available", comment: "Update")
35	      content.body = NSLocalizedString("Version [version] is now available", comment: "Update").replacingOccurrences(of: "[version]", with: update.displayVersionString)
36	      let request = UNNotificationRequest(identifier: Self.updateNotificationIdentifier, content: content, trigger: nil)
37	      UNUserNotificationCenter.current().add(request)
38	    }
39	  }
40	
41	  func standardUserDriverDidReceiveUserAttention(forUpdate update: SUAppcastItem) {
42	    NSApp.dockTile.badgeLabel = ""
43	    UNUserNotificationCenter.current().removeDeliveredNotifications(withIdentifiers: [Self.updateNotificationIdentifier])
44	  }
45	
46	  func standardUserDriverWillFinishUpdateSession() {
47	    NSApp.setActivationPolicy(.accessory)
48	  }
49	
50	  func userNotificationCenter(_ center: UNUserNotificationCenter, didReceive response: UNNotificationResponse, withCompletionHandler completionHandler: @escaping () -> Void) {
51	    if response.notification.request.identifier == Self.updateNotificationIdentifier && response.actionIdentifier == UNNotificationDefaultActionIdentifier {
52	      updateController.updater.checkForUpdates()
53	    }
54	
55	    completionHandler()
56	  }
57	
58	  func applicationWillFinishLaunching(_ notification: Notification) {
59	    panel = SquirrelPanel(position: .zero)
60	    refreshStatusItem()
61	    addObservers()
62	  }
63	
64	  func applicationWillTerminate(_ notification: Notification) {
65	    // swiftlint:disable:next notification_center_detachment
66	    NotificationCenter.default.removeObserver(self)
67	    DistributedNotificationCenter.default().removeObserver(self)
68	    panel?.hide()
69	    if let item = statusItem {
70	      NSStatusBar.system.removeStatusItem(item)
71	      statusItem = nil
72	    }
73	  }
74	
75	  func updateStatusIcon(asciiMode: Bool, schemaLabel: String?) {
76	    DispatchQueue.main.async { [weak self] in
77	      self?.applyStatusIcon(asciiMode: asciiMode, schemaLabel: schemaLabel)
78	    }
79	  }
80	
81	  func deploy() {
82	    print("Start maintenance...")
83	    self.shutdownRime()
84	    self.startRime(fullCheck: true)
85	    self.loadSettings()
86	  }
87	
88	  func syncUserData() {
89	    print("Sync user data")
90	    _ = rimeAPI.sync_user_data()
91	  }
92	
93	  func openLogFolder() {
94	    NSWorkspace.shared.open(SquirrelApp.logDir)
95	  }
96	
97	  func openRimeFolder() {
98	    NSWorkspace.shared.open(SquirrelApp.userDir)
99	  }
