101	  func checkForUpdates() {
102	    if updateController.updater.canCheckForUpdates {
103	      print("Checking for updates")
104	      updateController.updater.checkForUpdates()
105	    } else {
106	      print("Cannot check for updates")
107	    }
108	  }
