110	  func openWiki() {
111	    NSWorkspace.shared.open(Self.rimeWikiURL)
112	  }
113	
114	  static func showMessage(msgText: String?) {
115	    let center = UNUserNotificationCenter.current()
116	    center.requestAuthorization(options: [.alert, .provisional]) { _, error in
117	      if let error = error {
118	        print("User notification authorization error: \(error.localizedDescription)")
119	      }
120	    }
121	    center.getNotificationSettings { settings in
122	      if (settings.authorizationStatus == .authorized || settings.authorizationStatus == .provisional) && settings.alertSetting == .enabled {
123	        let content = UNMutableNotificationContent()
124	        content.title = NSLocalizedString("Squirrel", comment: "")
125	        if let msgText = msgText {
126	          content.subtitle = msgText
127	        }
128	        content.interruptionLevel = .active
129	        let request = UNNotificationRequest(identifier: Self.notificationIdentifier, content: content, trigger: nil)
130	        center.add(request) { error in
131	          if let error = error {
132	            print("User notification request error: \(error.localizedDescription)")
133	          }
134	        }
135	      }
136	    }
137	  }
